package org.springframework.web.server; public class ResponseStatusException extends RuntimeException { private final org.springframework.http.HttpStatus s; private final String r; public ResponseStatusException(org.springframework.http.HttpStatus s, String m){super(m); this.s=s; this.r=m;} public org.springframework.http.HttpStatus getStatusCode(){ return s; } public String getReason(){ return r; } }